const w = weaponDef(state);
if (w) {
  if (w.id.includes('pistol') || w.id.includes('rifle') || w.id === 'glock_18') return 'gun';
  if (w.id.includes('shortbow') || w.id.includes('longbow') || w.id === 'shortbow') return 'ranged';
}
return 'melee';

if (mode === 'ranged' || mode === 'gun') {
  const suffix = mode === 'ranged' ? '_arrow' : '_round';
  const ammo = state.equipment?.ammo;
  if (!ammo || !ammo.id.endsWith(suffix) || ammo.qty <= 0) return false;
  // Quillrook quiver passive: 20% chance the shot is not consumed.
  if (state.equipment?.neck?.id === 'quillrook_quiver' && Math.random() < 0.2) return true;
  ammo.qty -= 1;
  if (ammo.qty <= 0) state.equipment!.ammo = null;
  extras.equip = { ammo: state.equipment?.ammo ?? null };
  return true;
}
